import React, { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { getUserActivities } from '../../features/Activity/ActivitySlice';
import { useParams } from 'react-router-dom';

const Activity = () => {
  const dispatch = useDispatch();
  const { activityLogs = [], loading, error } = useSelector((state) => state.activity);
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const { id } = useParams();

  const [openLogs, setOpenLogs] = useState({});

  useEffect(() => {
    if (id) {
      dispatch(getUserActivities(id));
    }
  }, [dispatch, id]);

  const toggleLog = (logId) => {
    setOpenLogs((prev) => ({
      ...prev,
      [logId]: !prev[logId],
    }));
  };

  if (loading) return <div className="text-center text-xl">Loading...</div>;

  if (error) {
    const errorMessage = error?.message || 'An error occurred';
    return <div className="text-center text-xl text-red-600">{errorMessage}</div>;
  }

  if (!activityLogs.length && !loading) {
    return <div className="text-center text-lg text-gray-600">No activity found for this admin.</div>;
  }

  return (
    <div className="container mx-auto p-4">
      <h2 className="text-3xl font-semibold text-center mb-6">Admin Activity</h2>
      <div className="bg-white shadow-md rounded-lg p-4">
        <ul className="space-y-4">
          {activityLogs.map((log) => (
            <li key={log._id} className="border-b border-gray-300 pb-4">
              <div className="flex justify-between items-center mb-2">
                <div>
                  <strong className="text-xl text-gray-800">{log.action}</strong>
                  <span className="text-gray-500 ml-4">{log.timestamp}</span>
                </div>
                <button
                  onClick={() => toggleLog(log._id)}
                  className="text-blue-500 text-sm"
                >
                  {openLogs[log._id] ? 'Hide Details' : 'Show Details'}
                </button>
              </div>
              {openLogs[log._id] && (
                <div className="mt-2">
                  <p className="text-gray-700">
                    <strong>Resource:</strong> <span className="font-semibold">{log.resource}</span>
                  </p>
                  {log.details && (
                    <div className="mt-2 border-l-2 pl-4 border-gray-200">
                      <h4 className="text-lg font-semibold mb-2">Details:</h4>
                      {Object.entries(log.details).map(([key, value]) => (
                        <div key={key} className="mb-2">
                          {typeof value === 'object' && value !== null ? (
                            <div>
                              <strong>{key}:</strong>
                              <div className="ml-4">
                                {Object.entries(value).map(([nestedKey, nestedValue]) => (
                                  <p key={nestedKey} className="text-gray-600">
                                    <strong>{nestedKey}:</strong> {String(nestedValue)}
                                  </p>
                                ))}
                              </div>
                            </div>
                          ) : (
                            <p className="text-gray-600">
                              <strong>{key}:</strong> {String(value)}
                            </p>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </li>
          ))}
        </ul>
      </div>
      <div className="flex justify-between items-center mt-6">
        <button
          onClick={() => setPage(page - 1)}
          disabled={page === 1}
          className="px-4 py-2 bg-gray-300 text-gray-800 rounded-lg disabled:opacity-50"
        >
          Previous
        </button>
        <div className="text-gray-700">Page {page}</div>
        <button
          onClick={() => setPage(page + 1)}
          disabled={activityLogs.length < limit}
          className="px-4 py-2 bg-gray-300 text-gray-800 rounded-lg disabled:opacity-50"
        >
          Next
        </button>
      </div>
    </div>
  );
};

export default Activity;
